# Module providing shopping cart functionality
from models import Product, Customer

class ShoppingCart:
    total: float

    def __init__(self):
        self.total = 0.0

    def add_item(self, product: Product) -> None:
        self.total += product.price

    def get_total(self) -> float:
        return self.total

    def checkout(self, customer: Customer) -> bool:
        if customer.can_afford(self.total):
            customer.deduct(self.total)
            return True
        return False
